// src/pages/Menu.jsx
import React, { useEffect, useState } from 'react';
import api from '../api/axios';
import '../styles/style.css';
import Footer from '../components/Footer/Footer';
import Navbar from '../components/Navbar/Navbar';

export default function Menu() {
  const [menuData, setMenuData] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [openItemId, setOpenItemId] = useState(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('All');
  const [feedback, setFeedback] = useState('');
  const [feedbackSubmitted, setFeedbackSubmitted] = useState(false);
  const [showScrollTop, setShowScrollTop] = useState(false);
  const [userRole, setUserRole] = useState('customer');

  // Get user role
  useEffect(() => {
    const role = localStorage.getItem('userRole') || 'customer';
    setUserRole(role);

    // Save current user to localStorage.users if not already present
    const currentUser = localStorage.getItem('currentUser') || 'Anonymous';
    const storedUsers = JSON.parse(localStorage.getItem('users')) || [];
    if (!storedUsers.find(u => u.name === currentUser)) {
      const updatedUsers = [...storedUsers, { id: Date.now(), name: currentUser }];
      localStorage.setItem('users', JSON.stringify(updatedUsers));
    }
  }, []);

  // Fetch menu items
  useEffect(() => {
    const fetchMenu = async () => {
      try {
        const res = await api.get('/items');
        const grouped = res.data.reduce((acc, item) => {
          const cat = item.category || 'Uncategorized';
          if (!acc[cat]) acc[cat] = [];
          acc[cat].push({
            ...item,
            rating: (Math.random() * 2 + 3).toFixed(1),
            popular: Math.random() > 0.7
          });
          return acc;
        }, {});

        const groupedArr = Object.keys(grouped).map((cat, idx) => ({
          category: { category_id: idx, category_name: cat },
          items: grouped[cat]
        }));

        setMenuData(groupedArr);
        setLoading(false);
      } catch (err) {
        console.error(err);
        setError('Failed to load menu items.');
        setLoading(false);
      }
    };

    fetchMenu();
  }, []);

  const toggleDescription = id => setOpenItemId(openItemId === id ? null : id);

  // Handle feedback submission (localStorage)
  const handleFeedbackSubmit = () => {
    if (!feedback.trim()) return alert('Please write some feedback.');
    const newFeedback = {
      id: Date.now(),
      name: localStorage.getItem('currentUser') || 'Anonymous',
      comment: feedback.trim(),
      date: new Date().toISOString()
    };

    const storedFeedback = JSON.parse(localStorage.getItem('feedbackList')) || [];
    const updatedFeedback = [newFeedback, ...storedFeedback];
    localStorage.setItem('feedbackList', JSON.stringify(updatedFeedback));

    setFeedback('');
    setFeedbackSubmitted(true);
    setTimeout(() => setFeedbackSubmitted(false), 4000);
  };

  const filteredMenu = menuData
    .map(section => ({
      ...section,
      items: section.items.filter(item =>
        item.item_name.toLowerCase().includes(searchTerm.toLowerCase()) &&
        (selectedCategory === 'All' || section.category.category_name === selectedCategory)
      )
    }))
    .filter(section => section.items.length > 0);

  const categories = ['All', ...menuData.map(s => s.category.category_name)];

  const getRandomDescription = itemName => {
    const desc = [
      `Delicious ${itemName} made fresh daily.`,
      `A tasty choice, ${itemName} will delight your taste buds.`,
      `${itemName} prepared with the finest ingredients.`,
      `Our special ${itemName}, loved by everyone!`,
    ];
    return desc[Math.floor(Math.random() * desc.length)];
  };

  return (
    <div style={{ background: '#fff5e6', minHeight: '100vh', paddingBottom: '50px', position: 'relative' }}>
      <Navbar />

      <div className="menu-container" style={{ display: 'flex', gap: '20px', padding: '30px', alignItems: 'flex-start' }}>
        {/* Menu Left */}
        <div className="menu-left" style={{ flex: 2 }}>
          <h1>🍽️ Our Menu</h1>

          {/* Search & Filter */}
          <div style={{ marginBottom: '20px', display: 'flex', gap: '10px', flexWrap: 'wrap' }}>
            <input
              type="text"
              placeholder="Search items..."
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
              style={{ padding: '8px', borderRadius: '5px', border: '1px solid #ccc', flex: 1 }}
            />
            <select
              value={selectedCategory}
              onChange={e => setSelectedCategory(e.target.value)}
              style={{ padding: '8px', borderRadius: '5px', border: '1px solid #ccc' }}
            >
              {categories.map(cat => <option key={cat} value={cat}>{cat}</option>)}
            </select>
          </div>

          {loading && <p>⏳ Loading menu items...</p>}
          {error && <p className="error-text">{error}</p>}

          {/* Display grouped items */}
          {!loading && !error && filteredMenu.map(section => (
            <div key={section.category.category_id} style={{ marginBottom: '25px' }}>
              <h2>{section.category.category_name}</h2>
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: '12px' }}>
                {section.items.map(item => (
                  <div key={item.item_id} style={{ flex: '1 1 200px', position: 'relative' }}>
                    <button
                      onClick={() => toggleDescription(item.item_id)}
                      style={{
                        width: '100%',
                        padding: '12px',
                        borderRadius: '8px',
                        border: '1px solid #333',
                        background: '#fff8f0',
                        fontWeight: 'bold',
                        cursor: 'pointer'
                      }}
                    >
                      {item.item_name} – ${parseFloat(item.price).toFixed(2)}
                      <span style={{ float: 'right', fontSize: '0.85em', color: '#b87b1c' }}>
                        {item.popular && '🔥 '}⭐{item.rating}
                      </span>
                    </button>
                    {openItemId === item.item_id &&
                      <p style={{ marginTop: '5px', fontStyle: 'italic', color: '#555' }}>
                        {getRandomDescription(item.item_name)}
                      </p>
                    }
                  </div>
                ))}
              </div>
            </div>
          ))}

          {/* Feedback form only visible for customers */}
          {userRole === 'customer' && (
            <div style={{ marginTop: '25px', padding: '15px', background: '#fff4e0', borderRadius: '10px' }}>
              <h4 style={{ color: '#b87b1c' }}>💬 Share Your Feedback</h4>
              <textarea
                placeholder="Write your feedback..."
                value={feedback}
                onChange={e => setFeedback(e.target.value)}
                rows={4}
                style={{ width: '100%', padding: '10px', borderRadius: '6px', border: '1px solid #ccc', marginBottom: '10px' }}
              />
              <button
                onClick={handleFeedbackSubmit}
                style={{ background: '#d35400', color: '#fff', padding: '10px', borderRadius: '6px', border: 'none', cursor: 'pointer', width: '100%', fontWeight: 'bold' }}
              >
                Submit Feedback
              </button>
              {feedbackSubmitted && <p style={{ color: 'green', marginTop: '10px' }}>✅ Thank you for your feedback!</p>}
            </div>
          )}
        </div>

        {/* Right Images */}
        <div className="menu-right" style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: '12px' }}>
          <img src="/Images/Salads.jpeg" alt="Salads" style={{ borderRadius: '8px', width: '100%' }} />
          <img src="/Images/Beverages1.jpeg" alt="Beverages" style={{ borderRadius: '8px', width: '100%' }} />
          <img src="/Images/ShrimpsPlatter.jpeg" alt="Snacks" style={{ borderRadius: '8px', width: '100%' }} />
          <img src="/Images/BurgerMain.jpeg" alt="Burgers" style={{ borderRadius: '8px', width: '100%' }} />
        </div>
      </div>

      {showScrollTop && (
        <button
          onClick={() => window.scrollTo({ top: 0, behavior: 'smooth' })}
          style={{
            position: 'fixed', right: '20px', bottom: '30px', width: '45px', height: '45px',
            borderRadius: '50%', background: '#d35400', color: '#fff', border: 'none', fontSize: '24px', cursor: 'pointer'
          }}
        >
          ↑
        </button>
      )}

      <Footer />
    </div>
  );
}
